"""
Step ID: step06
Step Name: effect_size_analysis
RQ: results/ch7/7.7.2
Generated: 2026-01-09

PURPOSE:
Compute comprehensive effect sizes with clinical interpretation thresholds.
Calculate Cohen's d, Hedges' g, omega-squared, and probability of superiority
for all pairwise group comparisons.

EXPECTED INPUTS:
  - results/ch7/7.7.2/data/step05_anova_results.csv
  - results/ch7/7.7.2/data/step05_posthoc_comparisons.csv
  - results/ch7/7.7.2/data/step04_demographic_data.csv

EXPECTED OUTPUTS:
  - results/ch7/7.7.2/data/step06_effect_sizes.csv
  - results/ch7/7.7.2/data/step06_clinical_profiles.csv
  - results/ch7/7.7.2/data/step06_clinical_interpretation.txt

g_code REASONING:
- Compute multiple effect size metrics for robustness
- Bootstrap CIs for effect sizes (1000 iterations, seed=42)
- Clinical interpretation based on Cohen's thresholds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy import stats as scipy_stats
from itertools import combinations
import traceback

PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

from tools.analysis_stats import compute_effect_sizes
from tools.validation import validate_effect_sizes

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step06_effect_size_analysis.log"

def log(msg):
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

if __name__ == "__main__":
    try:
        log("[START] Step 06: Effect Size Analysis")

        # Load data
        log("[LOAD] Loading ANOVA results and demographic data...")
        anova_df = pd.read_csv(RQ_DIR / "data" / "step05_anova_results.csv")
        demo_df = pd.read_csv(RQ_DIR / "data" / "step04_demographic_data.csv")

        log(f"[LOADED] {len(anova_df)} ANOVA results, {len(demo_df)} participants")

        # Identify demographic variables (exclude UID, Group*, Discrepancy*)
        exclude_cols = ['UID'] + [c for c in demo_df.columns if c.startswith('Group') or c.startswith('Discrepancy')]
        demo_vars = [col for col in demo_df.columns if col not in exclude_cols]

        # Identify grouping schemes
        grouping_schemes = {}
        if 'Group_RAVLT_Total' in demo_df.columns:
            grouping_schemes['RAVLT_Total'] = 'Group_RAVLT_Total'
        elif 'Group' in demo_df.columns:
            grouping_schemes['RAVLT_Total'] = 'Group'
        if 'Group_RAVLT_Pct_Ret' in demo_df.columns:
            grouping_schemes['RAVLT_Pct_Ret'] = 'Group_RAVLT_Pct_Ret'

        log(f"[INFO] Variables: {demo_vars}")
        log(f"[INFO] Grouping schemes: {grouping_schemes}")

        # Compute effect sizes for all pairwise comparisons
        log("[COMPUTE] Calculating effect sizes for all pairwise comparisons...")

        effect_size_results = []
        clinical_profiles = []

        for scheme_label, group_col in grouping_schemes.items():
            groups = demo_df[group_col].unique()
            log(f"\n[ES] === {scheme_label} (column: {group_col}) ===")

            for var in demo_vars:
                # Remove missing values
                df_complete = demo_df[[group_col, var]].dropna()
                df_complete = df_complete.rename(columns={group_col: 'Group'})

                # All pairwise comparisons
                for group1, group2 in combinations(groups, 2):
                    data1 = df_complete[df_complete['Group'] == group1][var].values
                    data2 = df_complete[df_complete['Group'] == group2][var].values

                    if len(data1) >= 3 and len(data2) >= 3:
                        # Compute effect sizes using catalogued function
                        es_result = compute_effect_sizes(
                            group1=data1,
                            group2=data2,
                            test_type='t-test'
                        )

                        # Bootstrap CIs
                        np.random.seed(42)
                        n_iterations = 1000
                        boot_cohens_d = []

                        for _ in range(n_iterations):
                            boot_data1 = np.random.choice(data1, size=len(data1), replace=True)
                            boot_data2 = np.random.choice(data2, size=len(data2), replace=True)

                            pooled_sd = np.sqrt(((len(boot_data1)-1)*boot_data1.std()**2 + (len(boot_data2)-1)*boot_data2.std()**2) / (len(boot_data1)+len(boot_data2)-2))
                            if pooled_sd > 0:
                                d = (boot_data1.mean() - boot_data2.mean()) / pooled_sd
                                boot_cohens_d.append(d)

                        ci_lower, ci_upper = np.percentile(boot_cohens_d, [2.5, 97.5])

                        # Clinical significance
                        abs_d = abs(es_result.get('cohens_d', 0))
                        if abs_d < 0.2:
                            clinical_sig = 'negligible'
                        elif abs_d < 0.5:
                            clinical_sig = 'small'
                        elif abs_d < 0.8:
                            clinical_sig = 'medium'
                        else:
                            clinical_sig = 'large'

                        effect_size_results.append({
                            'metric': scheme_label,
                            'variable': var,
                            'comparison': f"{group1} vs {group2}",
                            'cohens_d': es_result.get('cohens_d', np.nan),
                            'hedges_g': es_result.get('hedges_g', np.nan),
                            'CI_lower': ci_lower,
                            'CI_upper': ci_upper,
                            'clinical_significance': clinical_sig
                        })

                        log(f"[ES] {scheme_label}/{var} ({group1} vs {group2}): d={es_result.get('cohens_d', np.nan):.3f}, 95% CI=[{ci_lower:.3f}, {ci_upper:.3f}], {clinical_sig}")

                # Clinical profiles
                group_stats = df_complete.groupby('Group')[var].agg(['mean', 'std', 'count'])
                for group_name in groups:
                    if group_name in group_stats.index:
                        clinical_profiles.append({
                            'metric': scheme_label,
                            'Group': group_name,
                            'variable': var,
                            'mean': group_stats.loc[group_name, 'mean'],
                            'sd': group_stats.loc[group_name, 'std'],
                            'n': group_stats.loc[group_name, 'count']
                        })

        effect_sizes_df = pd.DataFrame(effect_size_results)
        profiles_df = pd.DataFrame(clinical_profiles)

        # Clinical interpretation text
        interpretation_text = f"""CLINICAL INTERPRETATION - RQ 7.7.2 Effect Sizes

Generated: {pd.Timestamp.now().isoformat()}

Effect Size Thresholds (Cohen):
  - Negligible: |d| < 0.2
  - Small: 0.2 <= |d| < 0.5
  - Medium: 0.5 <= |d| < 0.8
  - Large: |d| >= 0.8
"""

        for scheme_label in grouping_schemes.keys():
            scheme_df = effect_sizes_df[effect_sizes_df['metric'] == scheme_label] if 'metric' in effect_sizes_df.columns else effect_sizes_df
            interpretation_text += f"\n=== {scheme_label} ===\n"
            interpretation_text += "Summary by Clinical Significance:\n"

            for sig_level in ['negligible', 'small', 'medium', 'large']:
                n_comps = (scheme_df['clinical_significance'] == sig_level).sum()
                interpretation_text += f"  - {sig_level.capitalize()}: {n_comps} comparisons\n"

            interpretation_text += "\nClinically Meaningful Differences (Medium/Large):\n"
            meaningful = scheme_df[scheme_df['clinical_significance'].isin(['medium', 'large'])]
            if len(meaningful) > 0:
                for _, row in meaningful.iterrows():
                    interpretation_text += f"  - {row['variable']} ({row['comparison']}): d={row['cohens_d']:.3f} [{row['clinical_significance']}]\n"
            else:
                interpretation_text += "  - None detected\n"

        # Save outputs
        log("[SAVE] Saving effect size results...")

        output_es = RQ_DIR / "data" / "step06_effect_sizes.csv"
        effect_sizes_df.to_csv(output_es, index=False, encoding='utf-8')
        log(f"[SAVED] {output_es.name} ({len(effect_sizes_df)} rows)")

        output_profiles = RQ_DIR / "data" / "step06_clinical_profiles.csv"
        profiles_df.to_csv(output_profiles, index=False, encoding='utf-8')
        log(f"[SAVED] {output_profiles.name} ({len(profiles_df)} rows)")

        output_interpretation = RQ_DIR / "data" / "step06_clinical_interpretation.txt"
        with open(output_interpretation, 'w', encoding='utf-8') as f:
            f.write(interpretation_text)
        log(f"[SAVED] {output_interpretation.name}")

        # Validation
        log("[VALIDATION] Running validate_effect_sizes...")
        validation_result = validate_effect_sizes(
            effect_sizes_df=anova_df,
            f2_column='eta_squared'  # Using eta_squared as proxy for f2
        )

        if validation_result.get('valid', False):
            log("[PASS] Effect sizes validated")
        else:
            log(f"[WARNING] Validation warnings: {validation_result}")

        log("[SUCCESS] Step 06 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
